                $valid = true;
                $test_errors = [];
                
                for ($i = 0; $i < $num; $i++) {
                    $stat = $zip->statIndex($i);
                    if ($stat === false) {
                        $test_errors[] = "Entry $i: Cannot read metadata";
                        $valid = false;
                        continue;
                    }
                    $data = $zip->getFromIndex($i);
                    if ($data === false) {
